import { useEffect, useState } from "react";
import api from "../api";

/** ========= Config ========= **/
const PAGE_SIZE = 10;
const ROLES = ["ADMIN", "SALES", "ACCOUNTANT"];
const STATUSES = ["ACTIVE", "INACTIVE"];

/** Chuẩn hoá Page<?> từ BE */
function normalizePage(d) {
    if (Array.isArray(d)) return { list: d, pages: 1 };
    return {
        list: d?.content || [],
        pages: typeof d?.totalPages === "number" ? d.totalPages : 1,
    };
}

/** debounce nhỏ cho ô tìm kiếm */
function useDebounce(value, delay = 400) {
    const [v, setV] = useState(value);
    useEffect(() => {
        const t = setTimeout(() => setV(value), delay);
        return () => clearTimeout(t);
    }, [value, delay]);
    return v;
}

function emptyForm() {
    return {
        username: "",
        fullName: "",
        email: "",
        phone: "",
        role: "SALES",
        status: "ACTIVE", // ACTIVE/INACTIVE
        password: "",
        confirm: "",
        resetPassword: false, // chỉ dùng khi sửa
    };
}

